mapper.select:
/* findByWorkplaceMemberId */
SELECT ID, WORKPLACE_MEMBER_ID, USE_NATIONAL_PENSION, USE_HEALTH_INSURANCE,
       USE_LONG_TERM_CARE, USE_EMPLOYMENT_INSURANCE, USE_INCOME_TAX, TAX_FREE_AMOUNT,
       CREATED_AT, UPDATED_AT
FROM EMPLOYEE_INSURANCE_SETTINGS
WHERE WORKPLACE_MEMBER_ID = #{workplaceMemberId}

mapper.update:
/* update */
UPDATE EMPLOYEE_INSURANCE_SETTINGS
SET USE_NATIONAL_PENSION    = #{useNationalPension},
    USE_HEALTH_INSURANCE    = #{useHealthInsurance},
    USE_LONG_TERM_CARE      = #{useLongTermCare},
    USE_EMPLOYMENT_INSURANCE = #{useEmploymentInsurance},
    USE_INCOME_TAX          = #{useIncomeTax},
    TAX_FREE_AMOUNT         = #{taxFreeAmount}
WHERE WORKPLACE_MEMBER_ID = #{workplaceMemberId}
